INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('judicial-d35ec6db-moex-00097', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-113-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '甲對乙之侵權行為損害賠償請求權，已於上個月罹於消滅時效。下列敘述，何者正確？ 甲之請求權已經消滅 乙於賠償後，得以不知時效為理由請求返還 乙得拒絕賠償 甲得現在起訴乙，以中斷消滅時效', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "00de5652f9d0", "answer_pdf_sha1": "bda7d653402b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "204", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 4, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00098', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-113-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '下列何者非屬身分行為？ 甲乙結婚之行為 父親甲贈與其子乙新臺幣200萬元，供其支付購屋頭期款之贈與行為 甲乙結婚，共同訂立夫妻財產契約 法定繼承人拋棄繼承之行為', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "00de5652f9d0", "answer_pdf_sha1": "bda7d653402b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "204", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 5, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00099', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-113-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '依民法第92條第1項規定，被詐欺而為意思表示，表意人得撤銷其意思表示。關於此撤銷權，下 列敘述，何者錯誤？ 屬於形成權    該意思表示經撤銷後，視為自始無效 適用一年之消滅時效期間  其撤銷不得對抗善意第三人', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "00de5652f9d0", "answer_pdf_sha1": "bda7d653402b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "204", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 6, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00100', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-113-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '於符合得行使下列各種權利要件時，何者非屬由一方當事人向相對人為意思表示即生效力之情 形？ 表示行使解除權之意思  表示免除債務之意思 表示主張抵銷之意思  表示行使債權人撤銷權之意思', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "00de5652f9d0", "answer_pdf_sha1": "bda7d653402b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "204", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 7, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00101', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-113-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '甲向乙承租其所有之A屋。依民法規定，下列敘述，何者錯誤？ 若乙不同意，甲不得將A屋全部轉租第三人丙 若甲乙雙方無反對之約定，甲得將A屋一部分轉租第三人丙 若甲將A屋違法轉租第三人丙，甲丙間之租賃契約仍為有效 若甲將A屋合法轉租第三人丙，則因丙應負責任之事由所生之損害，甲不負賠償責任', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "00de5652f9d0", "answer_pdf_sha1": "bda7d653402b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "204", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 8, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00102', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-113-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '甲住於A地，與住於B地之乙，於C地締結甲所有並保管於D地之X名畫買賣契約，但二人疏 未約定交付該畫之地點。清償期屆至時，甲應於何地交付該畫於乙？ A地  B地  C地  D地', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "00de5652f9d0", "answer_pdf_sha1": "bda7d653402b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "204", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 9, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00103', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-113-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '關於旅遊營業人變更旅遊內容，下列敘述，何者正確？ 旅遊營業人僅得於因不可抗力或不可歸責之事由時，始得變更旅遊內容 旅遊營業人任意變更旅遊行程內容項目，旅客僅得終止契約，不得解除契約 旅遊營業人在銷售行程資料載明「航班及飯店僅供參考」，即得因目的地當地情形隨時變更航班 與飯店 旅遊營業人任意變更旅遊行程內容項目，旅客僅得減少價金', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "00de5652f9d0", "answer_pdf_sha1": "bda7d653402b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "204", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 10, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00104', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-113-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '關於契約成立方式之一，乃要約與承諾合致。下列何者非屬要約？ 超商架上標定售價之麵包  土豆伯沿街叫賣好吃之燒土豆 投幣式販賣機中標示價格之飲品  水果攤販標示花蓮大西瓜一顆500元', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "00de5652f9d0", "answer_pdf_sha1": "bda7d653402b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "204", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 11, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00105', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-113-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '依民法規定，下列關於保證之敘述，何者錯誤？ 保證債務，除契約另有訂定外，不包含主債務之利息 保證人得主張主債務契約不成立之抗辯 保證人得以主債務人對於債權人已具抵銷適狀之債權，主張抵銷 主債務人受破產宣告者，保證人不得主張先訴抗辯權', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "00de5652f9d0", "answer_pdf_sha1": "bda7d653402b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "204", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 12, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00106', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-113-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '甲、乙訂立甲所有A屋之買賣契約，乙並已先支付部分價金於甲。未料在甲應交付A屋於乙、並 為移轉所有權登記前，A屋因受鄰屋屋主丙不慎引發火災波及而滅失。下列敘述，何者錯誤？ 甲得請求丙賠償因A屋滅失所受之損害 乙得請求甲返還其已支付之部分價金 乙得請求丙賠償其因A屋滅失所受之損害 甲免負交付A屋及移轉A屋所有權於乙之義務', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "00de5652f9d0", "answer_pdf_sha1": "bda7d653402b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "204", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 13, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL)
